class Solution:
    def compareVersion(self, v1: str, v2: str) -> int:
        a, b = v1.split('.'), v2.split('.')
        n = max(len(a), len(b))
        for i in range(n):
            x = int(a[i]) if i < len(a) else 0
            y = int(b[i]) if i < len(b) else 0
            if x > y: return 1
            if x < y: return -1
        return 0

