int compareVersion(char* v1, char* v2) {
    char *p1 = v1, *p2 = v2;
    while (*p1 || *p2) {
        long a = 0, b = 0;
        while (*p1 && *p1 != '.') a = a * 10 + (*p1++ - '0');
        if (*p1) p1++;
        while (*p2 && *p2 != '.') b = b * 10 + (*p2++ - '0');
        if (*p2) p2++;
        if (a > b) return 1;
        if (a < b) return -1;
    }
    return 0;
}
